#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100000

// Structure to represent a graph
typedef struct {
    int numVertices;
    int** adjMatrix;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adjMatrix = (int**) malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjMatrix[i] = (int*) malloc(numVertices * sizeof(int));
        for (int j = 0; j < numVertices; j++) {
            graph->adjMatrix[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    graph->adjMatrix[u][v] = 1;
    graph->adjMatrix[v][u] = 1;
}

// Function to find the shortest path between two cities
int* shortestPath(Graph* graph, int u, int v) {
    int* path = (int*) malloc(graph->numVertices * sizeof(int));
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }
    int queue[graph->numVertices];
    int front = 0, rear = 0;
    queue[rear++] = u;
    visited[u] = 1;
    while (front < rear) {
        int current = queue[front++];
        if (current == v) {
            break;
        }
        for (int i = 0; i < graph->numVertices; i++) {
            if (graph->adjMatrix[current][i] == 1 && visited[i] == 0) {
                queue[rear++] = i;
                visited[i] = 1;
            }
        }
    }
    int index = 0;
    while (rear > 0) {
        path[index++] = queue[--rear];
    }
    return path;
}

// Function to count the number of different trips
int countTrips(Graph* graph) {
    int count = 0;
    for (int i = 0; i < graph->numVertices; i++) {
        for (int j = 0; j < graph->numVertices; j++) {
            if (i != j) {
                int* path = shortestPath(graph, i, j);
                int length = 0;
                while (path[length] != -1 && length < graph->numVertices) {
                    length++;
                }
                // Check if the trip is similar to any previously counted trip
                count++;
            }
        }
    }
    return count;
}

int main() {
    int N;
    scanf("%d", &N);
    Graph* graph = createGraph(N);
    for (int i = 0; i < N - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u - 1, v - 1);
    }
    int count = countTrips(graph);
    printf("%d\n", count);
    return 0;
}

