// Structure to represent a graph
struct Graph {
    int numVertices;
    vector<vector<int>> adjList;
};

// Function to create a graph
Graph createGraph(int numVertices) {
    Graph graph;
    graph.numVertices = numVertices;
    graph.adjList.resize(numVertices);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int u, int v) {
    graph.adjList[u].push_back(v);
    graph.adjList[v].push_back(u);
}

// Function to find the shortest path between two cities
vector<int> shortestPath(Graph& graph, int u, int v) {
    vector<int> path;
    vector<bool> visited(graph.numVertices, false);
    queue<int> q;
    q.push(u);
    visited[u] = true;
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        if (current == v) {
            break;
        }
        for (int i = 0; i < graph.adjList[current].size(); i++) {
            if (!visited[graph.adjList[current][i]]) {
                q.push(graph.adjList[current][i]);
                visited[graph.adjList[current][i]] = true;
            }
        }
    }
    return path;
}

// Function to count the number of different trips
int countTrips(Graph& graph) {
    int count = 0;
    for (int i = 0; i < graph.numVertices; i++) {
        for (int j = 0; j < graph.numVertices; j++) {
            if (i != j) {
                vector<int> path = shortestPath(graph, i, j);
                count++;
            }
        }
    }
    return count;
}

