import java.util.Scanner;
import java.util.Queue;
import java.util.LinkedList;

public class Main {
    static class Graph {
        int numVertices;
        int[][] adjMatrix;

        public Graph(int numVertices) {
            this.numVertices = numVertices;
            this.adjMatrix = new int[numVertices][numVertices];
        }
    }

    public static Graph createGraph(int numVertices) {
        return new Graph(numVertices);
    }

    public static void addEdge(Graph graph, int u, int v) {
        graph.adjMatrix[u][v] = 1;
        graph.adjMatrix[v][u] = 1;
    }

    public static int[] shortestPath(Graph graph, int u, int v) {
        int[] path = new int[graph.numVertices];
        boolean[] visited = new boolean[graph.numVertices];
        Queue<Integer> q = new LinkedList<>();
        q.add(u);
        visited[u] = true;
        while (!q.isEmpty()) {
            int current = q.poll();
            if (current == v) {
                break;
            }
            for (int i = 0; i < graph.numVertices; i++) {
                if (graph.adjMatrix[current][i] == 1 && !visited[i]) {
                    q.add(i);
                    visited[i] = true;
                }
            }
        }
        return path;
    }

    public static int countTrips(Graph graph) {
        int count = 0;
        for (int i = 0; i < graph.numVertices; i++) {
            for (int j = 0; j < graph.numVertices; j++) {
                if (i != j) {
                    int[] path = shortestPath(graph, i, j);
                    count++;
                }
            }
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        Graph graph = createGraph(N);
        for (int i = 0; i < N - 1; i++) {
            int u = sc.nextInt() - 1;
            int v = sc.nextInt() - 1;
            addEdge(graph, u, v);
        }
        int count = countTrips(graph);
        System.out.println(count);
    }
}

