            const current = queue.shift();
            if (current === v) {
                break;
            }
            for (const neighbor of this.adjList[current]) {
                if (!visited[neighbor]) {
                    queue.push(neighbor);
                    visited[neighbor] = true;
                }
            }
        }
        return path;
    }

    countTrips() {
        let count = 0;
        for (let i = 0; i < this.numVertices; i++) {
            for (let j = 0; j < this.numVertices; j++) {
                if (i !== j) {
                    const path = this.shortestPath(i, j);
                    count++;
                }
            }
        }
        return count;
    }
